// L'HTTP Request a récupéré les données — on les parse ici
const data = $input.first().json;

// Log pour voir la structure exacte
console.log('Total AOs disponibles:', data.total);
console.log('Nombre reçus:', data.rows);

const notices = data.procnotices || [];
if (notices.length === 0) {
  return [{ json: { status: 'VIDE', message: 'Aucun AO retourné' } }];
}

// Log du premier AO pour voir tous les champs disponibles
console.log('Champs du premier AO:', Object.keys(notices[0]).join(', '));
console.log('Premier AO complet:', JSON.stringify(notices[0], null, 2));

// Pays prioritaires TargetUp
const PAYS = [
  "morocco","senegal","cote d'ivoire","ivory coast","djibouti",
  "mauritania","mauritius","cameroon","gabon","benin","togo",
  "mali","burkina faso","niger","guinea","congo","rwanda",
  "tunisia","algeria","egypt","kenya","ghana","ethiopia"
];

function isPrioritaire(n) {
  const text = [
    n.countryname, n.project_ctry_name, n.borrower_country, n.country
  ].filter(Boolean).join(' ').toLowerCase();
  return PAYS.some(p => text.includes(p));
}

function detectType(n) {
  const g = (n.procurement_group || '').toLowerCase();
  const m = (n.procurement_method_name || '').toLowerCase();
  if (g === 'cs' || m.includes('consult') || m.includes('qcbs') || m.includes('qbs')) return 'Services de Conseil';
  if (g === 'indv' || m.includes('individual')) return 'Consultant Individuel';
  if (g === 'go' || m.includes('goods')) return 'Fournitures';
  if (g === 'wk' || m.includes('works')) return 'Travaux';
  return n.procurement_method_name || n.procurement_group || 'Non précisé';
}

function detectProfil(n) {
  const text = [n.noticeTitle, n.bid_description].filter(Boolean).join(' ').toLowerCase();
  if (text.includes('individual') || text.includes('indv')) return 'Consultant Individuel';
  if (text.includes('firm') || text.includes('cabinet') || text.includes('company')) return 'Cabinet / Société';
  if (text.includes('expert') || text.includes('specialist')) return 'Expert / Spécialiste';
  if (text.includes('ngo') || text.includes('ong')) return 'ONG / Association';
  return 'Non précisé';
}

// Filtrer par pays prioritaires
const filtres = notices.filter(n => isPrioritaire(n));
console.log('AOs pays prioritaires:', filtres.length, '/', notices.length);

// Si aucun pays prioritaire, retourner tous
const liste = filtres.length > 0 ? filtres : notices;

return liste.map(n => ({ json: {
  source: 'World Bank',
  reference: n.id || 'N/A',
  projet_id: n.project_id || 'N/A',
  titre: n.noticeTitle || n.bid_description || 'Sans titre',
  description: (n.bid_description || '').replace(/<[^>]+>/g,'').trim().slice(0,800),
  nom_projet: n.projectname || 'N/A',
  pays: n.countryname || n.project_ctry_name || n.borrower_country || 'Non précisé',
  date_publication: n.noticedate || 'N/A',
  date_limite: n.submission_deadline_date || 'N/A',
  type_ao: detectType(n),
  type_profil_demande: detectProfil(n),
  methode_passation: n.procurement_method_name || n.procurement_group || 'N/A',
  contact_nom: n.contact_name || 'Non disponible',
  contact_email: n.contact_email || 'Non disponible',
  contact_telephone: n.contact_phone || 'Non disponible',
  lien_projet: n.project_id ? `https://projects.worldbank.org/en/projects-operations/project-detail/${n.project_id}` : '',
  lien_ao: n.id ? `https://projects.worldbank.org/en/projects-operations/procurement/noticedetail?id=${n.id}` : '',
  lien_pdf: n.url || '',
  date_extraction: new Date().toISOString()
}}));
